    controller_t controller;
    controller_init(&controller);

    if (controller.inlet_open != false) {
        printf("FAIL: Inlet should be closed at boot\n");
        return;
    }
    if (controller.heater_on != false) {
        printf("FAIL: Heater should be off at boot\n");
        return;
    }
    if (controller.state != CONTROLLER_STATE_SAFE_IDLE) {
        printf("FAIL: State should be SAFE_IDLE at boot\n");
        return;
    }

    printf("PASS: Boot default state is correct\n");
}

void test_controller_fill_low_level(void)
{
    printf("Test: Low level (50) should open inlet and turn off heater\n");
    controller_t controller;
    controller_init(&controller);

    /* Simulate LEVEL 50, TEMP 40 */
    controller_input_t input = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 50,
        .temperature_c = 40,
        .now_ms = 1000000U,
    };

    controller_output_t output = controller_step(&controller, input);

    if (output.inlet_open != true) {
        printf("FAIL: Inlet should be open at level 50\n");
        return;
    }
    if (output.heater_on != false) {
        printf("FAIL: Heater should be off at level 50\n");
        return;
    }
    if (output.state != CONTROLLER_STATE_FILLING) {
        printf("FAIL: State should be FILLING at low level\n");
        return;
    }

    printf("PASS: Low level command correct\n");
}

void test_controller_fill_safe_level(void)
{
    printf("Test: Safe level (65, TEMP 40) should close inlet and turn on heater\n");
    controller_t controller;
    controller_init(&controller);

    /* Simulate LEVEL 65, TEMP 40 */
    controller_input_t input = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 65,
