        return;
    }

    printf("PASS: Sensor timeout handled correctly\n");
}

void test_controller_fill_all_valid_inputs(void)
{
    printf("Test: All valid inputs cycle through expected states\n");
    controller_t controller;
    controller_init(&controller);

    /* Initial state */
    if (controller.inlet_open != false) {
        printf("FAIL: Inlet should be closed at start\n");
        return;
    }
    if (controller.heater_on != false) {
        printf("FAIL: Heater should be off at start\n");
        return;
    }

    /* Fill phase: LEVEL 50 */
    controller_input_t level1 = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 50,
        .temperature_c = 40,
        .now_ms = 1000000U,
    };
    controller_output_t out1 = controller_step(&controller, level1);

    if (out1.inlet_open != true) {
        printf("FAIL: Inlet should open at low level\n");
        return;
    }

    /* Heating phase: LEVEL 65, TEMP 40 */
    controller_input_t level2 = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 65,
        .temperature_c = 40,
        .now_ms = 1000000U,
    };
    controller_output_t out2 = controller_step(&controller, level2);

    if (out2.inlet_open != false) {
        printf("FAIL: Inlet should close at safe level\n");
        return;
    }
    if (out2.heater_on != true) {
        printf("FAIL: Heater should turn on at safe level with low temp\n");
        return;
    }

    /* Heating stop: LEVEL 65, TEMP 47 */
    controller_input_t level3 = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 65,
        .temperature_c = 47,
        .now_ms = 1000000U,
    };
    controller_output_t out3 = controller_step(&controller, level3);

    if (out3.heater_on != false) {
        printf("FAIL: Heater should off at upper band\n");
        return;
    }

    /* Hold phase: LEVEL 65, TEMP 49 */
    controller_input_t level4 = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 65,
        .temperature_c = 49,
        .now_ms = 1000000U,
    };
    controller_output_t out4 = controller_step(&controller, level4);

    if (out4.heater_on != false) {
        printf("FAIL: Heater should off when temp rising\n");
        return;
    }

    /* Reset phase: No inputs */
    controller_output_t reset1 = controller_step(&controller, controller_input_t{.kind=CONTROLLER_INPUT_NONE});

    if (reset1.state != CONTROLLER_STATE_SAFE_IDLE) {
        printf("FAIL: State should reset on none input\n");
        return;
    }

    /* Low temp reset */
    controller_input_t low_temp = {
        .kind = CONTROLLER_INPUT_TEMPERATURE,
        .temperature_c = 30,
        .now_ms = 1000000U,
    };
    controller_output_t out_low = controller_step(&controller, low_temp);

    if (out_low.state != CONTROLLER_STATE_SAFE_IDLE) {
        printf("FAIL: State should reset on low temp\n");
        return;
    }

    /* High level reset */
    controller_input_t high_level = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 70,
        .temperature_c = 40,
        .now_ms = 1000000U,
    };
    controller_output_t out_high = controller_step(&controller, high_level);

    if (out_high.state != CONTROLLER_STATE_SAFE_IDLE) {
        printf("FAIL: State should reset on high level\n");
        return;
    }

    printf("PASS: All valid inputs cycle correctly\n");
}

void test_controller_fill_bad_input(void)
{
    printf("Test: Bad input (only temperature, no level) should go to safe idle\n");
    controller_t controller;
    controller_init(&controller);

    /* Simulate bad input with only temperature */
    controller_input_t temp_only = {
        .kind = CONTROLLER_INPUT_TEMPERATURE,
        .temperature_c = 30,
        .now_ms = 1000000U,
    };

    controller_output_t output = controller_step(&controller, temp_only);

    if (output.state != CONTROLLER_STATE_SAFE_IDLE) {
        printf("FAIL: State should reset on bad input\n");
        return;
    }

    printf("PASS: Bad input handled correctly\n");
}

int main(void)
{
    printf("Starting controller visible tests...\n");

    test_controller_boot_default_state();
    test_controller_fill_low_level();
    test_controller_fill_safe_level();
    test_controller_fill_heating_stop();
    test_controller_fill_rising_temp_early_off();
    test_controller_fill_sensor_timeout();
    test_controller_fill_all_valid_inputs();
    test_controller_fill_bad_input();

    printf("\nAll tests completed!\n");
    return 0;
}

