    /* Simulate boot by sending SAFE_IDLE state */
    char safe_idle_msg = "SAFE_IDLE\n";
    transport_send_line(safe_idle_msg);

    delay_ms(200);

    /* Send fill phase: LEVEL 50, TEMP 40 */
    protocol_serialize_act_inlet(true, test_sequence, sizeof(test_sequence));
    protocol_serialize_act_heater(false, test_sequence + 1, sizeof(test_sequence - 1));
    transport_send_line(test_sequence);

    char level_fill_msg = "LEVEL 50\nTEMP 40\n";
    transport_send_line(level_fill_msg);

    delay_ms(200);

    /* Send heating phase: LEVEL 65, TEMP 40 */
    protocol_serialize_act_inlet(false, test_sequence, sizeof(test_sequence));
    protocol_serialize_act_heater(true, test_sequence + 1, sizeof(test_sequence - 1));
    transport_send_line(test_sequence);

    char level_heat_msg = "LEVEL 65\nTEMP 40\n";
    transport_send_line(level_heat_msg);

    delay_ms(200);

    /* Send heater-off phase: LEVEL 65, TEMP 47 (rising temp should trigger early off) */
    protocol_serialize_act_inlet(false, test_sequence, sizeof(test_sequence));
    protocol_serialize_act_heater(false, test_sequence + 1, sizeof(test_sequence - 1));
    transport_send_line(test_sequence);

    char level_hold_msg = "LEVEL 65\nTEMP 47\n";
    transport_send_line(level_hold_msg);

    delay_ms(200);

    /* Send reset phase: no inputs (should go to safe idle) */
    protocol_serialize_act_inlet(false, test_sequence, sizeof(test_sequence));
    protocol_serialize_act_heater(false, test_sequence + 1, sizeof(test_sequence - 1));
    transport_send_line(test_sequence);

    char reset_msg = "RESET\n";
    transport_send_line(reset_msg);

    delay_ms(200);

    /* Heartbeat */
    protocol_serialize_act_inlet(false, test_sequence, sizeof(test_sequence));
    protocol_serialize_act_heater(false, test_sequence + 1, sizeof(test_sequence - 1));
    transport_send_line(test_sequence);

    printf("Probe sequence completed. Final states: inlet=%d, heater=%d\n",
           s_transport_context.controller.inlet_open,
           s_transport_context.controller.heater_on);

    /* Verify final state */
    if (s_transport_context.controller.inlet_open != false) {
        printf("FAIL: Final state should be all-off\n");
        uart_driver_delete(UART_TRANSPORT_PORT);
        return;
    }
    if (s_transport_context.controller.heater_on != false) {
        printf("FAIL: Final state should be all-off\n");
        uart_driver_delete(UART_TRANSPORT_PORT);
        return;
    }

    printf("PASS: Firmware probe completed successfully!\n");
}

/* ==================== HELPER FUNCTIONS ==================== */

static void delay_ms(uint32_t ms)
{
    while (portTimerLess(xTaskGetTickCount()) && ms > 0) {
        portDelayMicroseconds(1);
        ms--;
    }
}

void uart_transport_start(void)
{
    controller_init(&s_transport_context.controller);
    s_transport_context.rx_line_length = 0U;

    uart_config_t config = {
        .baud_rate = UART_TRANSPORT_BAUDRATE,
        .data_bits = UART_DATA_8_BITS,
        .parity = UART_PARITY_DISABLE,
        .stop_bits = UART_STOP_BITS_1,
        .flow_ctrl = UART_HW_FLOWCTRL_DISABLE,
        .source_clk = UART_SCLK_APB,
    };

    uart_driver_install(UART_TRANSPORT_PORT, UART_TRANSPORT_BUFFER_SIZE * 2, 0, 0, NULL, 0);
    uart_param_config(UART_TRANSPORT_PORT, &config);
    uart_set_pin(UART_TRANSPORT_PORT, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE);

    xTaskCreate(transport_task, "uart_transport", 4096, NULL, 5, NULL);
}

