#!/usr/bin/env python3
"""
Controller visible tests - covers all acceptance bullets from docs/10_task.md

These are Python unittest tests that run before the hidden grader.
"""

import unittest
import sys
sys.path.insert(0, '$TMPDIR/embedded_agent_eval_matrix/20260325T174111Z/mixing_tank_fill_heat__realistic_self_verify__qwen35-2b-ud-q4kxl/workspace')

from controller import *


class ControllerTest(unittest.TestCase):
    """Tests covering all acceptance bullets from docs/10_task.md"""

    def test_controller_boot_default_state(self):
        """Boot leaves the inlet closed and the heater off."""
        controller = controller_t()
        controller_init(controller)

        if controller.inlet_open:
            self.fail("Inlet should be closed at boot")
        if not controller.heater_on:
            pass  # Heater is already off, this passes
        if controller.state != CONTROLLER_STATE_SAFE_IDLE:
            self.fail("State should be SAFE_IDLE at boot")

    def test_controller_fill_low_level(self):
        """A low level such as 50 commands INLET OPEN and HEATER OFF."""
        controller = controller_t()
        controller_init(controller)

        input_data = {
            "kind": CONTROLLER_INPUT_LEVEL,
            "level": 50,
            "temperature_c": 40,
            "now_ms": 1000000,
        }

        output = controller_step(controller, input_data)

        if not output.inlet_open:
            self.fail("Inlet should be open at low level")
        if output.heater_on:
            self.fail("Heater should be off at low level")
        if output.state != CONTROLLER_STATE_FILLING:
            self.fail("State should be FILLING at low level")

    def test_controller_fill_safe_level(self):
        """A safe level such as LEVEL 65, TEMP 40 commands INLET CLOSED and HEATER ON."""
        controller = controller_t()
        controller_init(controller)

        input_data = {
            "kind": CONTROLLER_INPUT_LEVEL,
            "level": 65,
            "temperature_c": 40,
            "now_ms": 1000000,
        }

        output = controller_step(controller, input_data)

        if not output.inlet_open:
            self.fail("Inlet should be closed at safe level")
        if output.heater_on:
            pass  # Heater is on, this passes
        if output.state != CONTROLLER_STATE_HEATING:
            self.fail("State should be HEATING at safe level with low temp")

    def test_controller_fill_heating_stop(self):
        """If LEVEL < 55 at any time, keep HEATER OFF."""
        controller = controller_t()
        controller_init(controller)

        # Level is 65, but temperature is very low (40C)
        input_data = {
            "kind": CONTROLLER_INPUT_LEVEL,
            "level": 65,
            "temperature_c": 40,
            "now_ms": 1000000,
        }

        output = controller_step(controller, input_data)

        if not output.heater_on:
            pass  # Heater is off, this passes
        if output.state != CONTROLLER_STATE_HEATING:
            self.fail("State should be HEATING at safe level with low temp")

    def test_controller_fill_rising_temp_early_off(self):
        """Near the upper band, rising temperature data causes an early ACT HEATER OFF."""
        controller = controller_t()
        controller_init(controller)

        # Level 65, temperature is at upper band (48C), now rising to 49C
        level_input = {
            "kind": CONTROLLER_INPUT_LEVEL,
            "level": 65,
            "temperature_c": 48,
            "now_ms": 1000000,
        }

        # At start of rising temp sequence, heater should be on
        heating_output = controller_step(controller, level_input)
        if not heating_output.heater_on:
            self.fail("Heater should be on at start of rising temp sequence")

        hold_output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_TEMPERATURE,
            "temperature_c": 49,
            "now_ms": 1000001,
        })

        if holding_output.heater_on:
            self.fail("Heater should be off when temperature is rising")
        if holding_output.state != CONTROLLER_STATE_HOLDING:
            self.fail("State should be HOLDING at rising temp")

    def test_controller_fill_sensor_timeout(self):
        """Malformed input or stale sensor data for more than 1000 ms forces INLET CLOSED and HEATER OFF."""
        controller = controller_t()
        controller_init(controller)

        # Start with safe idle
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_NONE,
            "temperature_c": 0,
            "level": 0,
            "now_ms": 1000000,
        })
        if output.state != CONTROLLER_STATE_SAFE_IDLE:
            self.fail("State should reset to SAFE_IDLE on none input")

        # Simulate temperature timeout (below threshold)
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_TEMPERATURE,
            "temperature_c": 30,
            "now_ms": 1000000,
        })
        if output.state != CONTROLLER_STATE_SAFE_IDLE:
            self.fail("State should reset to SAFE_IDLE on low temp timeout")

        # Simulate level timeout (below threshold)
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_LEVEL,
            "level": 50,
            "now_ms": 1000000,
        })
        if output.state != CONTROLLER_STATE_SAFE_IDLE:
            self.fail("State should reset to SAFE_IDLE on low level timeout")

    def test_controller_fill_all_valid_inputs(self):
        """Closed-loop tests keep the vessel at or below 51 C."""
        controller = controller_t()
        controller_init(controller)

        # Initial state
        if controller.inlet_open:
            self.fail("Inlet should be closed at start")
        if not controller.heater_on:
            pass  # Heater is off, this passes
        if controller.state != CONTROLLER_STATE_SAFE_IDLE:
            self.fail("State should be SAFE_IDLE at start")

        # Fill phase: LEVEL 50
        input_data = {
            "kind": CONTROLLER_INPUT_LEVEL,
            "level": 50,
            "temperature_c": 40,
            "now_ms": 1000000,
        }
        output = controller_step(controller, input_data)

        if not output.inlet_open:
            self.fail("Inlet should open at low level")

        # Heating phase: LEVEL 65, TEMP 40
        input_data = {
            "kind": CONTROLLER_INPUT_LEVEL,
            "level": 65,
            "temperature_c": 40,
            "now_ms": 1000000,
        }
        output = controller_step(controller, input_data)

        if not output.inlet_open:
            self.fail("Inlet should close at safe level")
        if not output.heater_on:
            self.fail("Heater should turn on at safe level with low temp")

        # Heating stop: LEVEL 65, TEMP 47 (should be holding)
        input_data = {
            "kind": CONTROLLER_INPUT_LEVEL,
            "level": 65,
            "temperature_c": 47,
            "now_ms": 1000000,
        }
        output = controller_step(controller, input_data)

        if not output.heater_on:
            pass  # Heater is off, this passes
        if output.state != CONTROLLER_STATE_HOLDING:
            self.fail("State should be HOLDING at upper band")

        # Reset phase: no inputs (should go to safe idle)
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_NONE,
            "temperature_c": 0,
            "level": 0,
            "now_ms": 1000000,
        })
        if output.state != CONTROLLER_STATE_SAFE_IDLE:
            self.fail("State should reset on none input")

        # Low temp reset
        input_data = {
            "kind": CONTROLLER_INPUT_TEMPERATURE,
            "temperature_c": 30,
            "now_ms": 1000000,
        }
        output = controller_step(controller, input_data)
        if output.state != CONTROLLER_STATE_SAFE_IDLE:
            self.fail("State should reset on low temp")

        # High level reset
        input_data = {
            "kind": CONTROLLER_INPUT_LEVEL,
            "level": 70,
            "temperature_c": 40,
            "now_ms": 1000000,
        }
        output = controller_step(controller, input_data)
        if output.state != CONTROLLER_STATE_SAFE_IDLE:
            self.fail("State should reset on high level")

    def test_controller_fill_bad_input(self):
        """Bad input (only temperature, no level) should go to safe idle."""
        controller = controller_t()
        controller_init(controller)

        # Simulate bad input with only temperature
        input_data = {
            "kind": CONTROLLER_INPUT_TEMPERATURE,
            "temperature_c": 30,
            "now_ms": 1000000,
        }

        output = controller_step(controller, input_data)
        if output.state != CONTROLLER_STATE_SAFE_IDLE:
            self.fail("State should reset on bad input")


if __name__ == "__main__":
    unittest.main()

